// Agrupar notas por estudiante
const notasPorEstudiante = {};

for (const item of $input.all()) {
  const nota = item.json;
  const codigo = nota.codigo_estudiantil;

  if (!notasPorEstudiante[codigo]) {
    notasPorEstudiante[codigo] = {
      codigo_estudiantil: codigo,
      nombre_estudiante: nota.nombre_estudiante,
      apellidos_estudiante: nota.apellidos_estudiante,
      materia: nota.materia,
      grado: nota.grado,
      salon: nota.salon,
      notas: []
    };
  }

  notasPorEstudiante[codigo].notas.push({
    periodo: nota.periodo,
    nombre_actividad: nota.nombre_actividad,
    porcentaje: nota.porcentaje,
    nota: nota.nota,
    comentario: nota.comentario,
    orden: nota.orden
  });
}

// Convertir a array
return Object.values(notasPorEstudiante).map(est => ({ json: est }));

