// ========================================
// FUNCIÓN AUXILIAR: Nombre del período
// ========================================
function nombrePeriodo(num) {
  const nombres = {
    1: 'primer',
    2: 'segundo',
    3: 'tercer',
    4: 'cuarto'
  };
  return nombres[num] || num;
}

// ========================================
// FUNCIÓN AUXILIAR: Formatear porcentaje
// ========================================
function formatearPorcentaje(valor) {
  if (valor === null || valor === undefined) return null;
  const num = parseFloat(valor);
  if (Number.isNaN(num)) return null;
  if (num % 1 === 0) return num.toString();
  return num.toFixed(2).replace(/\.?0+$/, '');
}

// ========================================
// FUNCIÓN AUXILIAR: Formatear nota
// ========================================
function formatearNota(valor) {
  if (valor === null || valor === undefined) return '-';
  const num = parseFloat(valor);
  if (Number.isNaN(num)) return '-';
  return num.toFixed(2).replace(/\.?0+$/, '');
}

// ========================================
// DATOS DEL WEBHOOK Y ESTUDIANTE
// ========================================
const webhook = $('Webhook - Recibir desde Lovable').first().json.body;
const tipoBoton = webhook.tipo_boton;
const actividad = webhook.actividad;
const periodo = webhook.contexto.periodo;

const estudiante = $('Loop Over Items').first().json;

// ✅ NUNCA mostrar apellidos: solo nombre_estudiante
const nombreCompleto = `${estudiante.nombre_estudiante}`.trim();

const materia = estudiante.materia;
const notas = estudiante.notas || [];

// ========================================
// OBTENER TODOS LOS PADRES (NO SOLO UNO)
// ========================================
// ✅ IMPORTANTE: filtrar padres válidos (con id). Esto corrige el "Always Output Data".
const padres = $input.all()
  .map(item => item.json)
  .filter(p => p && p.id);

// ✅ Si no hay padres válidos, devolver array vacío (continuar con siguiente estudiante)
if (!padres.length) {
  return [];
}

// ========================================
// DETECTAR TIPO DE NOTIFICACIÓN
// ========================================
const hasFinalDefinitiva = notas.some(n => n.nombre_actividad === 'Final Definitiva');
const hasFinalPeriodo = notas.some(n => n.nombre_actividad === 'Final Periodo');

// ========================================
// GENERAR MENSAJE
// ========================================
let mensajeBase = '';

if (actividad && !hasFinalPeriodo && !hasFinalDefinitiva) {
  const nota = notas.find(n => n.nombre_actividad === actividad);

  if (!nota) {
    return [];
  }

  const notaValor = formatearNota(nota.nota);
  mensajeBase = `REPORTE DE NOTA:\n\n{PADRE}, te notifico que ${nombreCompleto} sacó ${notaValor} en la siguiente actividad de ${materia}:\n\n${actividad}`;

  if (nota.porcentaje) {
    const porcFormateado = formatearPorcentaje(nota.porcentaje);
    if (porcFormateado !== null) {
      mensajeBase += ` (${porcFormateado}% del periodo)`;
    }
  }

  if (nota.comentario) {
    mensajeBase += `\n\nComentario del/de la docente: ${nota.comentario}`;
  }
}

else if (hasFinalPeriodo && !hasFinalDefinitiva) {
  const finalPeriodo = notas.find(n => n.nombre_actividad === 'Final Periodo');
  const actividades = notas
    .filter(n => n.nombre_actividad !== 'Final Periodo')
    .sort((a, b) => (a.orden ?? 0) - (b.orden ?? 0));

  const sumaPorcentajes = actividades
    .filter(a => a.porcentaje !== null && a.porcentaje !== undefined)
    .reduce((sum, a) => sum + parseFloat(a.porcentaje), 0);

  const periodoCompleto = sumaPorcentajes === 100;

  if (periodoCompleto) {
    mensajeBase = `REPORTE COMPLETO DE PERIODO\n\n{PADRE}, así quedó el ${nombrePeriodo(periodo)} periodo de ${materia} de ${nombreCompleto}:\n\nActividades:\n`;

    actividades.forEach(act => {
      mensajeBase += `${act.nombre_actividad}`;
      if (act.porcentaje) {
        const porcFormateado = formatearPorcentaje(act.porcentaje);
        mensajeBase += ` (${porcFormateado}%)`;
      } else {
        mensajeBase += ` (-)`;
      }
      const notaValor = formatearNota(act.nota);
      mensajeBase += `: ${notaValor}\n`;
    });

    const finalValor = formatearNota(finalPeriodo?.nota);
    mensajeBase += `\nFinal del periodo: ${finalValor}`;

    if (finalPeriodo?.comentario) {
      mensajeBase += `\n\nComentario del/de la docente: ${finalPeriodo.comentario}`;
    }
  } else {
    mensajeBase = `REPORTE PARCIAL DE PERIODO\n\n{PADRE}, así va por ahora ${nombreCompleto} en el ${nombrePeriodo(periodo)} periodo de ${materia}:\n\nActividades:\n\n`;

    actividades.forEach(act => {
      mensajeBase += `${act.nombre_actividad}`;
      if (act.porcentaje) {
        const porcFormateado = formatearPorcentaje(act.porcentaje);
        mensajeBase += ` (${porcFormateado}%)`;
      } else {
        mensajeBase += ` (-)`;
      }
      const notaValor = formatearNota(act.nota);
      mensajeBase += `: ${notaValor}\n`;
    });

    if (finalPeriodo?.comentario) {
      mensajeBase += `\nComentario del/de la docente: ${finalPeriodo.comentario}`;
    }
  }
}

else if (hasFinalDefinitiva) {
  const finalDefinitiva = notas.find(n => n.nombre_actividad === 'Final Definitiva');
  const finalesPeriodo = notas
    .filter(n => n.nombre_actividad === 'Final Periodo')
    .sort((a, b) => (a.periodo ?? 0) - (b.periodo ?? 0));

  const todosCompletos = finalesPeriodo.length === 4;

  if (todosCompletos) {
    mensajeBase = `REPORTE COMPLETO DE AÑO\n\n{PADRE}, así quedó la nota definitiva de ${materia} de ${nombreCompleto}:\n\nPeriodo(s):\n`;

    finalesPeriodo.forEach(fp => {
      const nombreP = fp.periodo === 1 ? '1er Periodo' :
                      fp.periodo === 2 ? '2do Periodo' :
                      fp.periodo === 3 ? '3er Periodo' : '4to Periodo';
      const notaValor = formatearNota(fp.nota);
      mensajeBase += `${nombreP}: ${notaValor}\n`;
    });

    const defValor = formatearNota(finalDefinitiva?.nota);
    mensajeBase += `\nFinal definitiva: ${defValor}`;

    if (finalDefinitiva?.comentario) {
      mensajeBase += `\n\nComentario del/de la docente: ${finalDefinitiva.comentario}`;
    }
  } else {
    mensajeBase = `REPORTE PARCIAL DE AÑO\n\n{PADRE}, así van los periodos de ${materia} que ${nombreCompleto} tiene completos hasta ahora:\n\nPeriodo(s):\n\n`;

    finalesPeriodo.forEach(fp => {
      const nombreP = fp.periodo === 1 ? '1er Periodo' :
                      fp.periodo === 2 ? '2do Periodo' :
                      fp.periodo === 3 ? '3er Periodo' : '4to Periodo';
      const notaValor = formatearNota(fp.nota);
      mensajeBase += `${nombreP}: ${notaValor}\n`;
    });

    if (finalDefinitiva?.comentario) {
      mensajeBase += `\n\nComentario del/de la docente: ${finalDefinitiva.comentario}`;
    }
  }
}

// ========================================
// RETORNAR UN MENSAJE POR CADA PADRE
// ========================================
return padres.map(padre => ({
  json: {
    subscriber_id: padre.id,
    mensaje: mensajeBase.replace('{PADRE}', padre.padre_primer_nombre || 'Padre'),
    estudiante: nombreCompleto,
    tipo: hasFinalDefinitiva ? 'definitiva' : (hasFinalPeriodo ? 'periodo' : 'individual')
  }
}));
